#!/usr/bin/env node
/**
 * Session 5: 100 MC-Fragen (Recht).
 */
import fs from 'node:fs/promises'
import path from 'node:path'
import { fileURLToPath } from 'node:url'

const __dirname = path.dirname(fileURLToPath(import.meta.url))
const OUT = path.join(__dirname, 'fragen-updates.jsonl')
const STATE = path.join(__dirname, 'state.json')

const updates = [
  { id: '694a015a-e58c-40c9-aeac-d3b32c7226c1', fachbereich: 'Recht', musterlosung: 'Der Grundsatz der Formfreiheit (OR 11) gilt auch für Werkverträge — es gibt keine gesetzliche Schriftformpflicht. Ein mündlich geschlossener Werkvertrag ist gültig, wenn übereinstimmende Willenserklärungen und gültiger Inhalt vorliegen. Heinrichs Einwand ist nicht berechtigt — er muss zahlen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Es gibt keine gesetzliche CHF-Schwelle für Schriftform beim Werkvertrag.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Formfreiheit nach OR 11 — mündlicher Werkvertrag ist gültig.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftform ist nicht Gültigkeitsvoraussetzung beim Werkvertrag.' }, { feld: 'optionen', id: 'opt-3', text: 'Zeugen sind für den Vertragsschluss nicht nötig — Beweiszwecke wären ein anderes Thema.' } ] },
  { id: '6a4c3f62-e089-43f9-9c31-8bbacc747662', fachbereich: 'Recht', musterlosung: 'Art. 8 ZGB ist die Grundregel der Beweislast: Wer aus einer behaupteten Tatsache Rechte ableitet, muss diese Tatsache beweisen. In der Regel trägt der Kläger die Beweislast für die anspruchsbegründenden Tatsachen. Der Beklagte trägt sie für rechtshindernde oder rechtsvernichtende Einreden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Amtsermittlung — der Zivilprozess folgt der Verhandlungsmaxime.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Unschuldsvermutung im Zivilprozess — das gehört zum Strafrecht.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftlichkeit ist kein Erfordernis für Beweismittel — mehrere Beweismittel sind zugelassen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Wer Rechte ableitet, muss die Tatsachen beweisen (Art. 8 ZGB).' } ] },
  { id: '6aab2913-82c6-41a4-80bc-c87a6f97bc1e', fachbereich: 'Recht', musterlosung: 'Die Zuständigkeit ist eine Prozessvoraussetzung: Wird bei einem unzuständigen Gericht eingereicht, tritt dieses auf die Klage nicht ein oder das Urteil kann angefochten werden. Folge: Zeit- und Kostenverlust. Deshalb muss die Zuständigkeit zu Beginn des Verfahrens geklärt werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Kläger wählt nicht frei — die Zuständigkeitsregeln sind gesetzlich festgelegt.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Urteil unzuständiger Gerichte ist anfechtbar — Verfahren muss neu geführt werden.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Zuständigkeit ist Voraussetzung — ohne sie kein gültiges Urteil.' }, { feld: 'optionen', id: 'opt-3', text: 'Beweismittelzulassung hängt nicht von der sachlichen Zuständigkeit ab.' } ] },
  { id: '6ac42663-6888-47bc-af52-289de5d3c029', fachbereich: 'Recht', musterlosung: 'Art. 262 Abs. 2 OR erlaubt dem Vermieter, die Zustimmung zur Untermiete zu verweigern, wenn ihm wesentliche Nachteile entstehen. Kurzfristige Touristenvermietung (z.B. Airbnb) verursacht häufigen Personenwechsel, höheren Verschleiss und potenzielle Nachbarschaftsstörungen. Zusätzlich ist der Untermietzins oft missbräuchlich hoch im Vergleich zur Hauptmiete.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Mietzahlung allein heilt die missbräuchliche Untermiete nicht.' }, { feld: 'optionen', id: 'opt-1', text: 'Ganze Wohnung darf mit Zustimmung untervermietet werden — kein absolutes Verbot.' }, { feld: 'optionen', id: 'opt-2', text: 'Untermiete ist nicht immer erlaubt — an Voraussetzungen (Art. 262 OR) gebunden.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Wesentliche Nachteile (häufige Wechsel, Verschleiss) rechtfertigen Verweigerung.' } ] },
  { id: '6bb7d54d-48bb-4447-ab11-5c55488f70a6', fachbereich: 'Recht', musterlosung: 'Nach OR 357a gilt während der Laufzeit eines GAV die absolute Friedenspflicht: Kampfmassnahmen wie Streiks oder Boykotte sind unzulässig. Die Arbeitnehmerverbände sind verpflichtet, Streiks während GAV-Gültigkeit zu unterbinden. Der Arbeitsfrieden ist ein zentrales Element des GAV-Systems.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Friedenspflicht gilt absolut während GAV-Laufzeit — keine Ausnahmen wegen Verschlechterungen.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine AG-Zustimmung möglich — die Friedenspflicht ist ex lege vereinbart.' }, { feld: 'optionen', id: 'opt-2', text: 'Das Streikrecht ist für die GAV-Laufzeit aufgegeben — so die Idee des Arbeitsfriedens.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Friedenspflicht nach OR 357a verbietet Streiks während GAV.' } ] },
  { id: '6bbadec0-737f-48c8-bf81-4d00b2c7c898', fachbereich: 'Recht', musterlosung: 'Das Arbeitsgesetz (ArG) limitiert nicht die Tages-, sondern die Wochenarbeitszeit (45 Stunden für industrielle/Büro/Verkaufsbetriebe, 50 Stunden für übrige). Ein 10-Stunden-Tag ist zulässig, wenn die Wochenarbeitszeit nicht überschritten wird und die Ruhepausen (Art. 15 ArG) eingehalten werden.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '8h/Tag ist keine gesetzliche Obergrenze — nur Wochenlimit.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht unbegrenzt — Wochenlimite + Ruhezeiten sind zwingend.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Zulässig, wenn Wochenarbeitszeit nicht überschritten wird.' }, { feld: 'optionen', id: 'opt-3', text: '9h/Tag ist keine gesetzliche Grenze — nur Wochenlimit.' } ] },
  { id: '6be3e3df-fb96-4971-921f-2647aba2e7b3', fachbereich: 'Recht', musterlosung: 'Art. 97 Abs. 2 StGB sieht vor, dass bei Delikten an Minderjährigen die Verjährung frühestens mit dem 25. Altersjahr des Opfers beginnt. Die Regelung berücksichtigt, dass Minderjährige weniger selbstständig sind und die Täter oft nahestehende Personen sind. Eine emotionale und materielle Emanzipation kann nötig sein, bevor eine Anzeige möglich wird.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Selbständigkeit + nahestehende Täter + Emanzipation als Schutzgründe.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine automatische Polizeiüberwachung — die Regel hat andere Gründe.' }, { feld: 'optionen', id: 'opt-2', text: 'Es geht nicht um Erkennen — Minderjährige können Straftaten durchaus erkennen.' }, { feld: 'optionen', id: 'opt-3', text: 'Die Untersuchungsdauer ist nicht der Grund — es geht um Anzeigeerstattung durch das Opfer.' } ] },
  { id: '6c8d03e9-e556-48a6-ad53-6a1d98f32608', fachbereich: 'Recht', musterlosung: 'Richter Fonjallaz hielt Art. 29b PolG BE grundsätzlich für verfassungskonform, kritisierte aber die konkrete Anwendung. Die polizeiliche Sachverhaltsabklärung sei für die 13 Betroffenen ungenügend gewesen — bei blossem Lärm und Unrat ohne Aggressivität fehle es an einem gesicherten öffentlichen Interesse. Er verglich die Massnahme mit mittelalterlicher Verbannung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Folterverbot war nicht sein Argument — es ging um Wegweisung, nicht Gewaltanwendung.' }, { feld: 'optionen', id: 'opt-1', text: 'Er hielt Art. 29b PolG BE gerade für genügende Grundlage — kritisierte nur Anwendung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ungenügende Sachverhaltsabklärung + kein gesichertes öffentliches Interesse.' }, { feld: 'optionen', id: 'opt-3', text: 'Er argumentierte nicht mit Diskriminierungsverbot — sondern mit Sachverhalt und Interesse.' } ] },
  { id: '6c8e18a4-e502-4ddc-b77e-b63c10b22c5f', fachbereich: 'Recht', musterlosung: 'Jede Gesetzesnorm hat eine «Wenn-Dann»-Struktur. Art. 2 Abs. 2 ZGB: Wenn jemand ein Recht offenbar missbraucht (Tatbestandsmerkmal), dann findet dieses Verhalten keinen Rechtsschutz (Rechtsfolge). Das Gericht schützt rechtsmissbräuchliche Rechtsausübung nicht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: TBM offenbarer Rechtsmissbrauch, RF kein Rechtsschutz.' }, { feld: 'optionen', id: 'opt-1', text: 'Verdreht — kein Rechtsschutz ist die RF, nicht das TBM.' }, { feld: 'optionen', id: 'opt-2', text: 'Ein Recht zu haben ist noch kein TBM — erst der Missbrauch.' }, { feld: 'optionen', id: 'opt-3', text: 'Rechtsausübung als solche führt gerade zum Rechtsschutz — Missbrauch ist die Ausnahme.' } ] },
  { id: '6cc8ba99-2cc1-4188-ba12-8039dc842127', fachbereich: 'Recht', musterlosung: 'Stockwerkeigentum ist qualifiziertes Miteigentum (Art. 712a ff. ZGB). Jeder Stockwerkeigentümer hat ein Sonderrecht zur alleinigen Nutzung und Innenausstattung seiner Einheit. Der Anteil kann frei verkauft werden (kein gesetzliches Vorkaufsrecht ausser bei Vereinbarung). Die Stockwerkeigentümergemeinschaft ist keine juristische Person, sondern nur beschränkt rechts- und handlungsfähig (Art. 712l ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Qualifiziertes Miteigentum mit Sondereigentum an Einheit.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Sonderrecht zur Benutzung, Verwaltung und Innenausstattung.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Freie Verkaufbarkeit ohne gesetzliches Vorkaufsrecht anderer Eigentümer.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine juristische Person — nur beschränkt rechts- und handlungsfähig (Art. 712l).' } ] },
  { id: '6d0548a2-819f-4f4a-a423-1dc1794fed9f', fachbereich: 'Recht', musterlosung: 'Rechtskraft tritt auf zwei Wegen ein: Entweder die Rechtsmittelfrist läuft ungenutzt ab, oder die letzte Instanz hat entschieden (z.B. Bundesgerichtsurteil). Mit Rechtskraft ist das Urteil vollstreckbar und nicht mehr anfechtbar. Der Grundsatz «res iudicata pro veritate accipitur» gilt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Veröffentlichung oder 30 Tage sind nicht die gesetzlichen Rechtskraft-Voraussetzungen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Fristablauf oder letztinstanzliches Urteil — beide begründen Rechtskraft.' }, { feld: 'optionen', id: 'opt-2', text: 'Bezirksgericht ist nicht letzte Instanz — Rechtsmittel möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Parteizustimmung ist keine Voraussetzung — die Rechtskraft tritt ex lege ein.' } ] },
  { id: '6d720488-0076-4b39-97f4-ffbdf37b9334', fachbereich: 'Recht', musterlosung: 'Eine Obligation kann auf sieben Arten erlöschen: Erfüllung (OR 68), Übereinkunft/Erlass (OR 115), Neuerung (OR 116), Vereinigung (OR 118), Unmöglichwerden (OR 119), Verrechnung (OR 120) und Verjährung (OR 127 ff.). Diese Erlöschensgründe stehen teils nebeneinander, teils in systematischen Beziehungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: 7 Erlöschensarten (Erfüllung, Erlass, Neuerung, Vereinigung, Unmöglichkeit, Verrechnung, Verjährung).' }, { feld: 'optionen', id: 'opt-1', text: 'Zu wenig — das OR kennt mehr Erlöschensgründe als 3.' }, { feld: 'optionen', id: 'opt-2', text: 'Zu wenig — Neuerung, Verrechnung und andere fehlen.' }, { feld: 'optionen', id: 'opt-3', text: 'Zu viele — klassische Zählung ergibt 7 Erlöschensgründe.' } ] },
  { id: '6e2dccf8-172b-4139-85af-52fc6bb5894a', fachbereich: 'Recht', musterlosung: 'Art. 2 Abs. 1 ZGB verlangt, dass jedermann in der Ausübung seiner Rechte und Pflichten nach Treu und Glauben handelt. Das Gebot richtet sich an alle Rechtssubjekte — natürliche wie juristische Personen, Vertragspartner, Behörden. Es ist ein allgemeiner Grundsatz des gesamten Rechts.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Vertragsparteien — das Gebot gilt allgemein.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur juristische Personen — auch natürliche Personen sind adressiert.' }, { feld: 'optionen', id: 'opt-2', text: 'Richter sind gebunden, aber nicht ausschliesslich — auch alle anderen Rechtssubjekte.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Alle Rechtssubjekte sind adressiert.' } ] },
  { id: '6eecc6a5-4718-4a52-bb93-2bbc4b436ec3', fachbereich: 'Recht', musterlosung: 'Die klassische Gewaltenteilung nach Montesquieu unterscheidet drei Gewalten: Legislative (gesetzgebend — Parlament), Exekutive (ausführend — Bundesrat und Verwaltung) und Judikative (richterlich — Gerichte, oberste Instanz Bundesgericht). Die Gewalten kontrollieren sich gegenseitig (checks and balances).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Polizei/Gericht/Gefängnis sind Teile der Exekutive/Judikative — nicht Gewaltenteilung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Legislative, Exekutive, Judikative — klassische Dreiteilung.' }, { feld: 'optionen', id: 'opt-2', text: 'Das ist Schweizer Verfassungsordnung — nicht Gewaltenteilung.' }, { feld: 'optionen', id: 'opt-3', text: 'Das ist die föderale Ebenenteilung — nicht Gewaltenteilung.' } ] },
  { id: '6f176f69-901b-426e-b861-09a8664a056f', fachbereich: 'Recht', musterlosung: 'Der Grundsatz «Lex specialis derogat legi generali» bedeutet: Spezielleres Recht geht allgemeinerem Recht vor. Das Versicherungsvertragsgesetz (VVG) ist gegenüber dem OR Spezialrecht für Versicherungsverträge. Daher gilt die 4-Wochen-Frist des VVG — nicht die allgemeine 1-Jahres-Frist des OR.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Lex specialis derogat legi generali — VVG 4 Wochen gilt.' }, { feld: 'optionen', id: 'opt-1', text: 'Alter des Gesetzes ist nicht entscheidend — Spezialität zählt.' }, { feld: 'optionen', id: 'opt-2', text: 'Kürzere Frist gilt nicht per se — Spezialität entscheidet.' }, { feld: 'optionen', id: 'opt-3', text: 'Parallele Geltung ist ausgeschlossen — nur eine Frist gilt.' } ] },
  { id: '7012290f-79d7-4fed-9957-4cb530e7e204', fachbereich: 'Recht', musterlosung: 'Das Sachenrecht regelt die Rechte von Rechtssubjekten an Rechtsobjekten (Sachen). Dingliche Rechte können an beweglichen und unbeweglichen Sachen bestehen. Ein Kaufvertrag begründet ein obligatorisches Recht auf die Sache (inter partes), noch kein dingliches. Das Eigentum ist das umfassendste dingliche Recht (Art. 641 ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Sachenrecht regelt Beziehung Personen zu Sachen.' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — auch bewegliche Sachen kennen dingliche Rechte (z.B. Fahrnispfand).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Kaufvertrag begründet obligatorisches (relatives) Recht, nicht dingliches.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Eigentum ist das umfassendste dingliche Recht (Art. 641 ZGB).' } ] },
  { id: '70b750bf-2776-44b3-a5e4-8ea0081bc28f', fachbereich: 'Recht', musterlosung: 'Tagessatz = Monatseinkommen / 30 = CHF 7\'500 / 30 = CHF 250.–. Geldstrafe = 60 Tagessätze × CHF 250 = CHF 15\'000.–. Gemäss Art. 34 StGB beträgt ein Tagessatz zwischen CHF 30 und CHF 3\'000 und orientiert sich an den wirtschaftlichen Verhältnissen des Täters.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das entspricht einem Monatslohn — nicht 60 Tagessätze.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: 60 × CHF 250 = CHF 15\'000.–' }, { feld: 'optionen', id: 'opt-2', text: 'Zu hoch — Tagessatz ist 1/30 vom Monatseinkommen, nicht Monatslohn × 8.' }, { feld: 'optionen', id: 'opt-3', text: 'Deutlich zu hoch — das wäre 60 Monate, nicht 60 Tagessätze.' } ] },
  { id: '71d7562d-1083-4a4f-b204-7b3da546bbee', fachbereich: 'Recht', musterlosung: 'Das vereinfachte Verfahren (Art. 243 ff. ZPO) gilt für Streitwerte bis CHF 30\'000 sowie für bestimmte Streitigkeiten (Miete, Arbeit, Konsum). Es ist formloser, schneller und wird häufig von einem Einzelrichter geführt. Das ordentliche Verfahren gilt bei höherem Streitwert und wird von einem Kollegialgericht beurteilt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das vereinfachte Verfahren läuft nicht am Bundesgericht — es ist erstinstanzlich.' }, { feld: 'optionen', id: 'opt-1', text: 'Im ordentlichen Verfahren gibt es sehr wohl Beweisaufnahme — sogar formeller als im vereinfachten.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Bis CHF 30\'000, formloser, oft Einzelrichter.' }, { feld: 'optionen', id: 'opt-3', text: 'Das vereinfachte Verfahren gilt für zivile Streitigkeiten — nicht strafrechtliche.' } ] },
  { id: '71e250e6-430b-4883-aefd-95ede15c7c20', fachbereich: 'Recht', musterlosung: 'Das schweizerische Strafrecht kennt vier Rechtfertigungsgründe: Einwilligung des Betroffenen (z.B. Operation), gesetzlich erlaubte Handlung (Art. 14 StGB, z.B. polizeiliches Handeln), Notwehr (Art. 15 StGB) und Notstand (Art. 17/18 StGB). Liegt ein Rechtfertigungsgrund vor, ist die Tat nicht widerrechtlich und daher straflos.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unvollständig — auch gesetzlich erlaubte Handlung und Notstand zählen dazu.' }, { feld: 'optionen', id: 'opt-1', text: 'Selbsthilfe ist zivilrechtlich — die Rechtfertigungsgründe sind strafrechtlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur Notwehr — vier Rechtfertigungsgründe bestehen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Einwilligung + Art. 14 + Art. 15 + Art. 17/18 StGB.' } ] },
  { id: '72348ebd-0f3b-480b-83d5-7badc076fb92', fachbereich: 'Recht', musterlosung: 'Das StGB unterscheidet drei Deliktsarten: Verbrechen (Art. 10 Abs. 2, mehr als 3 Jahre Freiheitsstrafe), Vergehen (Art. 10 Abs. 3, bis 3 Jahre oder Geldstrafe) und Übertretungen (Art. 103, Busse). Gemeinnützige Arbeit bis 720 Stunden kommt bei Vergehen in Frage (Art. 37 StGB, mit Zustimmung des Täters).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Verbrechen ab 3 Jahren Freiheitsstrafe (Art. 10 Abs. 2 StGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Vergehen bis 3 Jahre oder Geldstrafe (Art. 10 Abs. 3 StGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — Übertretungen werden mit Busse bestraft (Art. 103), nicht Freiheitsstrafe.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gemeinnützige Arbeit bis 720 Stunden bei Vergehen (Art. 37 StGB).' } ] },
  { id: '727c595b-374f-48df-a7d9-43f143832da7', fachbereich: 'Recht', musterlosung: 'Ungeschriebenes Recht umfasst Gerichtspraxis (Präjudizien), Gewohnheitsrecht und richterliches Ermessen. Bundesgerichts-Praxis beim Führerausweisentzug, Handelsusanzen beim Zinsen-Rechnen (360/30 Tage) und richterliches Ermessen bei Unterhaltszahlungen basieren auf ungeschriebenem Recht. Ein Bundesgesetz wäre dagegen geschriebenes Recht.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Bundesgesetz ist geschriebenes Recht — kein ungeschriebenes.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Bundesgerichtspraxis = Präjudizien (ungeschriebenes Richterrecht).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Handelsusanz (360/30 Tage) = Gewohnheitsrecht.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Richterliches Ermessen bei Unterhalt ist ungeschriebene Rechtsfindung.' } ] },
  { id: '736cfab9-27ce-43a1-b467-27efb697fb48', fachbereich: 'Recht', musterlosung: 'Das Strafrecht unterscheidet bei der Tatbegehung durch mehrere Personen vier Formen: Mittäterschaft (gemeinschaftliche Begehung mit Tatherrschaft), mittelbare Täterschaft (jemand benutzt andere als Werkzeug), Anstiftung (Art. 24 StGB, jemand überredet zur Tat) und Gehilfenschaft (Art. 25 StGB, Hilfeleistung). Diese Unterscheidung ist wichtig für die Strafbarkeit und Strafzumessung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Lehrbuchkategorien — das sind beschreibende Begriffe.' }, { feld: 'optionen', id: 'opt-1', text: '«Zuschauer» ist keine rechtliche Kategorie — nur die 4 genannten zählen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Mittäterschaft, mittelbare Täterschaft, Anstiftung, Gehilfenschaft.' }, { feld: 'optionen', id: 'opt-3', text: '«Deckung» und «Planung» sind keine eigenen Kategorien im StGB.' } ] },
  { id: '738baf30-0695-439d-ab4d-19150797d165', fachbereich: 'Recht', musterlosung: 'Die Befolgungspflicht nach OR 321d gilt nicht für sittenwidrige oder gesetzwidrige Weisungen. Ein Verkauf rezeptpflichtiger Medikamente ohne Verordnung verstösst gegen das Heilmittelgesetz. Der Arbeitnehmer kann und sollte eine solche Weisung ablehnen, ohne Vertragsverletzung befürchten zu müssen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Gesetzwidrige Weisungen müssen nicht befolgt werden — Grenze der Weisungsbefugnis.' }, { feld: 'optionen', id: 'opt-1', text: 'Schriftform ist nicht erforderlich — die Ablehnung ist zulässig, unabhängig von der Form.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gesetzwidrige Weisung (Heilmittelgesetzverstoss) darf abgelehnt werden.' }, { feld: 'optionen', id: 'opt-3', text: 'Die AN-Verantwortung bleibt bestehen — blosses Abschieben funktioniert nicht.' } ] },
  { id: '741f28ae-b4d0-45aa-aee3-2d24203030fe', fachbereich: 'Recht', musterlosung: 'Die Gewaltenteilung verteilt die Staatsmacht auf drei voneinander unabhängige Gewalten (Legislative, Exekutive, Judikative). Dadurch wird Machtkonzentration verhindert. Die Gewalten kontrollieren sich gegenseitig (checks and balances), was Machtmissbrauch erschwert und die Freiheit der Bürger schützt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Effizienz ist nicht das Ziel — Machtkontrolle steht im Vordergrund.' }, { feld: 'optionen', id: 'opt-1', text: 'Direkte Gesetzgebung ist Volksrechte, nicht Gewaltenteilung.' }, { feld: 'optionen', id: 'opt-2', text: 'Inhaltliche Fairness ist nicht garantiert — nur Verfahrens- und Machtkontrolle.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Machtkonzentration verhindern + gegenseitige Kontrolle.' } ] },
  { id: '742a9228-036a-44ed-9a70-99cefc795f7c', fachbereich: 'Recht', musterlosung: 'Die Schwester ist bereits Besitzerin des Buches (Leihe). Für Besitz- und Eigentumsübertragung genügt die Schenkungserklärung von Heinz — eine physische Übergabe ist nicht mehr nötig. Sobald die Schwester die Schenkung annimmt, wird sie aus dem unselbständigen zum selbständigen Besitzer — und damit zur Eigentümerin. Diese Übergabeform heisst Brevi manu traditio.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Eine erneute physische Übergabe ist nicht nötig — Brevi manu traditio.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Eigentum sofort mit Schenkungserklärung, weil Brevi manu traditio.' }, { feld: 'optionen', id: 'opt-2', text: 'Doch — ausgeliehene Bücher können verschenkt werden, sogar vereinfacht.' }, { feld: 'optionen', id: 'opt-3', text: 'Schriftform ist bei der Handschenkung nicht Gültigkeitsvoraussetzung.' } ] },
  { id: '742ed219-92c3-4bc5-866d-24aaff58df8e', fachbereich: 'Recht', musterlosung: 'An einem Kaufvertrag sind zwei Rechtssubjekte beteiligt: Käufer und Verkäufer. Die Tischlerei Müller GmbH ist als juristische Person Käuferin, der Holzhändler Verkäufer. Tim handelt lediglich als Hilfsperson (Bote) für die GmbH — er ist nicht Vertragspartei. Die Eichenbretter sind das Rechtsobjekt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Unvollständig — auch die Käuferin ist Rechtssubjekt des Vertrags.' }, { feld: 'optionen', id: 'opt-1', text: 'Unvollständig — auch der Verkäufer ist Rechtssubjekt.' }, { feld: 'optionen', id: 'opt-2', text: 'Tim ist nur Bote — nicht Vertragspartei.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Beide — GmbH (Käuferin) und Holzhändler (Verkäufer).' } ] },
  { id: '74b5c6cb-a27b-49c5-afc3-bd4ed1d1d87c', fachbereich: 'Recht', musterlosung: 'Das Baurecht (Art. 779 ff. ZGB) ist eine Dienstbarkeit: Der Berechtigte darf auf oder unter einem fremden Grundstück ein Bauwerk errichten oder beibehalten. Der Eigentümer des Bauwerks und der des Bodens sind verschiedene Personen. Das Baurecht kann auf höchstens 100 Jahre begründet werden (Art. 779l ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das Recht am eigenen Grundstück folgt aus Eigentum — kein separates Baurecht nötig.' }, { feld: 'optionen', id: 'opt-1', text: 'Mieter-Umbau ist Mietrecht — nicht Baurecht im Sinne von ZGB 779.' }, { feld: 'optionen', id: 'opt-2', text: 'Das Baurecht trennt nicht Nachbargrundstücke — es trennt Bauwerk und Boden.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Bauwerk und Boden gehören verschiedenen Personen (Art. 779 ZGB).' } ] },
  { id: '74c97fa4-67d7-455c-99f2-cf800f42bcaa', fachbereich: 'Recht', musterlosung: 'Das ZGB unterscheidet zwei Formen gemeinschaftlichen Eigentums: Miteigentum (Art. 646 ff. ZGB) mit wertmässig-anteiligem Recht jedes Eigentümers und Gesamteigentum (Art. 652 ff. ZGB) ohne Einzelanteile. Das Stockwerkeigentum (Art. 712a ff.) ist eine besondere Form des Miteigentums.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Alleineigentum ist Gegensatz zu gemeinschaftlichem Eigentum — nicht dessen Form.' }, { feld: 'optionen', id: 'opt-1', text: 'Fahrnis-/Grundeigentum bezieht sich auf Sachtyp, nicht auf die Eigentumsform.' }, { feld: 'optionen', id: 'opt-2', text: 'Privat-/öffentliches Eigentum bezeichnet Eigentümertyp, nicht die Form.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Miteigentum (Art. 646 ff.) und Gesamteigentum (Art. 652 ff. ZGB).' } ] },
  { id: '75368e32-a6f4-4150-8d4c-874862a1ef99', fachbereich: 'Recht', musterlosung: 'Für möblierte Zimmer und gesondert vermietete Einstellplätze gilt nach Art. 266e OR eine Kündigungsfrist von zwei Wochen auf Ende eines Monats. Matteo kündigt am 10. Oktober — zwei Wochen auf Monatsende ergibt den 31. Oktober.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '1 Monat gilt nicht — Art. 266e OR sieht 2 Wochen vor.' }, { feld: 'optionen', id: 'opt-1', text: '3 Monate gelten für Wohnungen, nicht für möblierte Zimmer.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 2 Wochen auf Monatsende = 31. Oktober.' }, { feld: 'optionen', id: 'opt-3', text: 'Frei wählbares Datum — die Frist muss auf Ende Monat fallen.' } ] },
  { id: '7699faac-3a49-4406-9e76-6ef474f1b143', fachbereich: 'Recht', musterlosung: 'Während der Probezeit (max. 3 Monate, OR 335b) gilt eine gesetzliche Kündigungsfrist von 7 Tagen für beide Parteien. Dies ermöglicht eine rasche Beendigung, wenn die Zusammenarbeit nicht passt. Nach der Probezeit greifen die längeren Fristen nach OR 335c (1 Monat im 1. Dienstjahr, 2 Monate im 2.–9., 3 Monate ab 10. Dienstjahr).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '1 Tag ist zu kurz — 7 Tage sind gesetzliche Probezeitfrist.' }, { feld: 'optionen', id: 'opt-1', text: '1 Monat gilt erst nach Probezeit im 1. Dienstjahr.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 7 Tage nach OR 335b während der Probezeit.' }, { feld: 'optionen', id: 'opt-3', text: '3 Monate ist die Maximallaufzeit der Probezeit — nicht die Kündigungsfrist.' } ] },
  { id: '77e510bb-cbb4-4bd9-bd74-f8c613666437', fachbereich: 'Recht', musterlosung: 'Art. 2 Abs. 2 ZGB verbietet den offenbaren Rechtsmissbrauch. Typische Fallgruppen sind: nutzlose Rechtsausübung aus Schikane (Abrissbeispiel), Zweckentfremdung der juristischen Person (Durchgriffshaftung) und widersprüchliches Verhalten (venire contra factum proprium — z.B. Verjährungseinrede nach Verzicht). Blosse Vertragsverletzung ist dagegen kein Rechtsmissbrauch.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nutzlose Ausübung aus Schikane — klassischer Rechtsmissbrauch.' }, { feld: 'optionen', id: 'opt-1', text: 'Nichtbezahlung ist Vertragsverletzung, nicht Rechtsmissbrauch.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Durchgriffshaftung (Piercing the corporate veil) — Missbrauch der Rechtsform.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Verjährungseinrede nach Verzicht = widersprüchliches Verhalten.' } ] },
  { id: '783039a7-2bd2-4fb0-b943-4831d8303c7c', fachbereich: 'Recht', musterlosung: 'Bei Mängeln, die der Mieter nicht zu verantworten hat, stehen ihm nach Art. 259a–259f OR mehrere Rechte zu: Mängelbeseitigung verlangen (Art. 259b), Mietzinsreduktion (Art. 259d), Schadenersatz (Art. 259e) und ggf. fristlose Kündigung bei schweren Mängeln. Eine Strafanzeige ist zivilrechtlich nicht vorgesehen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Mängelbeseitigung auf Vermieter-Kosten (Art. 259b OR).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Mietzinsreduktion während Beeinträchtigung (Art. 259d OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Schadenersatz für Folgeschäden (Art. 259e OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Strafrechtliche Anzeige ist kein mietrechtliches Recht — unangemessene Eskalation.' } ] },
  { id: '78d1fc90-31a0-44fc-8009-65549c5397ad', fachbereich: 'Recht', musterlosung: 'Nach Art. 8 ZGB trägt die Beweislast, wer aus einer Tatsache Rechte ableitet. Der Arbeitgeber leitet aus dem behaupteten Diebstahl das Recht zur fristlosen Entlassung ab — also muss er beweisen, dass die Putzfrau die Täterin war. Ohne Beweis wäre die fristlose Kündigung ungerechtfertigt und würde zu Schadenersatz führen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine hälftige Teilung — die Beweislast liegt beim Ableitenden.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: AG leitet Kündigungsrecht aus Diebstahl ab und muss ihn beweisen (Art. 8 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Unschuldsvermutung im Zivilprozess — andere Beweislastregel.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Amtsermittlung im Zivilprozess — Verhandlungsmaxime.' } ] },
  { id: '78eb0350-da34-47b6-9817-d1721e2f8ec1', fachbereich: 'Recht', musterlosung: 'Das ZGB kennt drei Typen beschränkter dinglicher Rechte: Dienstbarkeiten (Servitute wie Wegrecht, Baurecht, Wohnrecht), Pfandrechte (Fahrnispfand, Grundpfand) und Grundlasten. Sie verschaffen kein Eigentum, sondern eine begrenzte Herrschaftsbefugnis über eine fremde Sache.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Miete ist kein dingliches, sondern ein obligatorisches Recht.' }, { feld: 'optionen', id: 'opt-1', text: 'Das sind Untertypen der Grundpfandrechte — nicht die Hauptkategorien.' }, { feld: 'optionen', id: 'opt-2', text: 'Das sind Beispiele für Dienstbarkeiten — nicht die drei Grundkategorien.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Dienstbarkeiten, Pfandrechte, Grundlasten.' } ] },
  { id: '78fad615-96df-4789-bd2f-cfb085d94c13', fachbereich: 'Recht', musterlosung: 'Die Sachgewährleistung nach OR 197 ff. ist die Pflicht des Verkäufers, dafür einzustehen, dass die Kaufsache die zugesicherten Eigenschaften hat und keine Mängel aufweist, die den Wert oder den Nutzen erheblich mindern. Bei Mängel kann der Käufer Wandlung, Minderung oder Ersatz verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Herstellergarantie ist vertraglich vereinbart — Sachgewährleistung ist gesetzlich.' }, { feld: 'optionen', id: 'opt-1', text: 'Versicherung ist ein Drittgeschäft — nicht Teil des Kaufvertrags.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Haftung des Verkäufers für Eigenschaften und Mängelfreiheit.' }, { feld: 'optionen', id: 'opt-3', text: 'Prüfungspflicht des Käufers ist OR 201 — nicht Sachgewährleistung des Verkäufers.' } ] },
  { id: '79eea822-39f9-49af-97b3-6af792a475af', fachbereich: 'Recht', musterlosung: 'Derselbe Sachverhalt kann straf- und zivilrechtliche Folgen haben. Strafrechtlich liegt eine mögliche fahrlässige Körperverletzung (Art. 125 StGB) und Fahren in angetrunkenem Zustand (Art. 91 SVG) vor — Verfolgung durch die Staatsanwaltschaft. Zivilrechtlich kann Petra Schadenersatz für Arztkosten verlangen (Art. 41 OR). Beide Verfahren laufen unabhängig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht nur Zivilprozess — auch ein Strafverfahren ist möglich.' }, { feld: 'optionen', id: 'opt-1', text: 'Verkehrsunfall ist strafrechtlich, nicht verwaltungsrechtlich.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Strafverfahren (Art. 125 StGB) + Zivilprozess (Art. 41 OR) möglich.' }, { feld: 'optionen', id: 'opt-3', text: 'Nicht nur Strafverfahren — Petra kann zusätzlich Schadenersatz fordern.' } ] },
  { id: '7a51821d-7e40-4c88-a9f3-d2c25a3a1ab4', fachbereich: 'Recht', musterlosung: 'Originärer (ursprünglicher) Eigentumserwerb entsteht ohne Rechtsnachfolge vom Vorbesitzer: Aneignung herrenloser Sachen (Art. 718), Ersitzung (Art. 728), Fund nach Fristablauf (Art. 722), Verarbeitung (Art. 726). Der Kauf ist dagegen derivativer Erwerb — das Eigentum wird vom bisherigen Eigentümer auf den Käufer übertragen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Aneignung herrenloser Sachen (Art. 718 ZGB) — klassisch originär.' }, { feld: 'optionen', id: 'opt-1', text: 'Kauf ist derivativ — Eigentum geht vom Verkäufer über.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Ersitzung nach 5 Jahren (Art. 728 ZGB) — originär.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Fund nach 5 Jahren ohne Eigentümer (Art. 722 ZGB) — originär.' } ] },
  { id: '7a5570ca-c78d-4e65-bf9b-b77e14a1b3da', fachbereich: 'Recht', musterlosung: 'Bei der Speziesschuld (einem individuell bestimmten Gegenstand) ist der Erfüllungsort nach OR 74 Abs. 2 Ziff. 2 dort, wo sich die Sache bei Vertragsschluss befand — hier also Bern. Dies ist eine Holschuld: Ursula muss das Klavier in Bern abholen. Die Holschuld ist der Regelfall bei individuell bestimmten Sachen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Wohnsitz des Schuldners gilt bei Gattungsschulden — nicht bei Speziesschulden.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein neutraler Ort im OR — das Gesetz bestimmt den Erfüllungsort klar.' }, { feld: 'optionen', id: 'opt-2', text: 'Wohnsitz des Gläubigers gilt bei Geldschulden — nicht bei Speziesschulden.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Standort der Sache (Bern) — Holschuld nach OR 74 Abs. 2 Ziff. 2.' } ] },
  { id: '7b6e4bda-8270-4621-a699-d2ab27e61e28', fachbereich: 'Recht', musterlosung: 'Die Schlichtung ist in der Schweiz vor einer Zivilklage grundsätzlich obligatorisch (Art. 197 ZPO). Schiedssprüche sind bindend und wie Gerichtsurteile vollstreckbar. Alternative Streitbeilegung (ADR) kann Zeit und Kosten sparen. Ein Mediator hat dagegen keine Entscheidungsgewalt — er unterstützt nur die Parteien bei einer eigenen Lösung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Obligatorische Schlichtung vor Zivilklage (Art. 197 ZPO).' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — der Mediator entscheidet gerade nicht; er vermittelt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Schiedssprüche sind rechtlich bindend und vollstreckbar.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: ADR oft günstiger und schneller als Gerichtsverfahren.' } ] },
  { id: '7d817344-8e1b-406d-8970-9c584a5c071a', fachbereich: 'Recht', musterlosung: 'Kevin ist 16 Jahre alt und fällt damit unter das Jugendstrafgesetz (JStG). Das Jugendstrafrecht stellt Schutz und Erziehung in den Vordergrund — nicht Vergeltung. Der Jugendliche kann trotzdem bestraft werden, aber die Massnahmen sind auf Erziehung und Resozialisierung ausgerichtet. Sein 19-jähriger Freund wird nach StGB beurteilt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine Bagatellgrenze — das JStG gilt unabhängig vom Deliktswert.' }, { feld: 'optionen', id: 'opt-1', text: 'Das Alter spielt sehr wohl eine Rolle — JStG für unter 18, StGB ab 18.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Kevin untersteht JStG — Schutzmassnahmen und Erziehung zentral.' }, { feld: 'optionen', id: 'opt-3', text: 'Minderjährige können bestraft werden — Jugendstrafrecht sieht Sanktionen vor.' } ] },
  { id: '7de598c6-442d-40bd-99aa-d54716bb07f1', fachbereich: 'Recht', musterlosung: 'Bei der Erbengemeinschaft bilden die Erben von Gesetzes wegen eine Gemeinschaft zur gesamten Hand (Art. 602 ZGB). Das geerbte Haus steht im Gesamteigentum. Über den Nachlass können die Erben nur gemeinsam verfügen. Einzelne können nicht über ihren rechnerischen Anteil verfügen — anders als beim Miteigentum.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Miteigentum — die Erbengemeinschaft ist zwingend Gesamteigentum.' }, { feld: 'optionen', id: 'opt-1', text: 'Stockwerkeigentum setzt spezielle Aufteilung voraus — nicht automatisch bei Erbe.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Erbengemeinschaft = Gesamteigentum (Art. 602 ZGB).' }, { feld: 'optionen', id: 'opt-3', text: 'Beide Schwestern sind Erben — kein Alleineigentum einer Einzelnen.' } ] },
  { id: '7e3d3d1a-3ea1-4695-af13-7570a3af8e50', fachbereich: 'Recht', musterlosung: 'Das Faustpfandrecht an einer beweglichen Sache entsteht erst mit der Übergabe der Sache an den Gläubiger (Art. 884 Abs. 3 ZGB). Der Pfandvertrag allein ist nur Verpflichtungsgeschäft. Die Übergabe ist das dingliche Verfügungsgeschäft, durch das der Gläubiger den Besitz und damit das Pfandrecht erlangt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Fälligkeit der Forderung ist unabhängig von der Pfandbegründung.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Pfandrecht entsteht mit Übergabe an den Gläubiger (Art. 884 Abs. 3 ZGB).' }, { feld: 'optionen', id: 'opt-2', text: 'Grundbucheintrag gilt für Grundpfand — nicht für Faustpfand.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Vertragsschluss allein reicht nicht — die Übergabe ist konstitutiv.' } ] },
  { id: '7e4747e8-9b7d-40e2-a524-664053f9776d', fachbereich: 'Recht', musterlosung: 'In der Region Bern-Thun gelten ortsübliche Kündigungstermine: 30. April und 31. Oktober. Die Kündigungsfrist für Wohnungen beträgt 3 Monate (Art. 266c OR). Für den 30. April hätte die Kündigung bis 31. Januar eingehen müssen — verpasst. Nächster möglicher Termin: 31. Oktober (Kündigung muss bis 31. Juli eingehen).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '31. Mai ist kein ortsüblicher Kündigungstermin in Bern-Thun.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: 30. April verpasst → nächster Termin 31. Oktober.' }, { feld: 'optionen', id: 'opt-2', text: '28. Februar ist kein ortsüblicher Kündigungstermin in Bern-Thun.' }, { feld: 'optionen', id: 'opt-3', text: '30. April wäre verpasst — Kündigung hätte bis 31. Januar eingehen müssen.' } ] },
  { id: '7e6f8b1e-8107-42be-8cb6-b01d60deaa7c', fachbereich: 'Recht', musterlosung: 'Ohne vereinbarten Fälligkeitstermin ist die Obligation nach OR 75 sofort nach Entstehung fällig und erfüllbar. Werner kann das Darlehen jederzeit zurückverlangen. Eine Mahnung zur Fälligkeit ist nicht nötig — OR 75 macht die Fälligkeit objektiv.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Sofortige Fälligkeit nach OR 75 ohne Terminvereinbarung.' }, { feld: 'optionen', id: 'opt-1', text: 'Mahnung ist für Verzug nötig — nicht für Fälligkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine automatische Jahresfrist — OR 75 sagt «sofort».' }, { feld: 'optionen', id: 'opt-3', text: 'Keine 30-Tage-Frist — OR 75 macht sofort fällig.' } ] },
  { id: '7ed584d9-c220-45eb-b7db-ea950435026a', fachbereich: 'Recht', musterlosung: 'Eine Strafanzeige ist eine Mitteilung an die Behörden über eine mutmassliche Straftat — jede Person kann sie erstatten. Ein Strafantrag ist bei Antragsdelikten (z.B. einfacher Diebstahl, Art. 139 Ziff. 1 StGB) erforderlich: Das Opfer muss innert 3 Monaten ausdrücklich Bestrafung verlangen (Art. 30 StGB). Ohne Antrag keine Strafverfolgung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Den Strafantrag muss der Verletzte stellen, nicht die Polizei.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Anzeige jederzeit durch jedermann, Antrag nur durch Opfer bei Antragsdelikten.' }, { feld: 'optionen', id: 'opt-2', text: 'Verbindlichkeit ist nicht das Unterscheidungskriterium — Ursprung und Delikt zählen.' }, { feld: 'optionen', id: 'opt-3', text: 'Die Begriffe sind nicht synonym — unterschiedliche Rechtsinstitute.' } ] },
  { id: '7f282410-9a0c-47cc-b6b8-316cd9f7bea6', fachbereich: 'Recht', musterlosung: 'Der Schuldnerverzug (OR 102 ff.) setzt Fälligkeit und Mahnung voraus (Abs. 1). Ausnahme ist der Verfalltag (Abs. 2) — hier tritt Verzug automatisch ein. Rechtsfolgen: verschuldensunabhängiger Verzugszins von 5% bei Geldschulden (OR 104) sowie verschuldensabhängige Haftung für nachträgliche Unmöglichkeit (OR 103).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Fälligkeit und Mahnung als Grundvoraussetzung (OR 102 Abs. 1).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Verfalltag-Ausnahme macht Mahnung entbehrlich (OR 102 Abs. 2).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: 5% Verzugszins auf Geldschulden (OR 104).' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Haftung für nachträgliche Unmöglichkeit (OR 103 Abs. 1).' } ] },
  { id: '7f3aad14-9540-4e45-8594-15084c031348', fachbereich: 'Recht', musterlosung: 'Geschäftsräume haben nach Art. 266d OR eine 6-monatige Kündigungsfrist. Die Kündigung muss 6 Monate vor dem Kündigungstermin beim Vermieter eingehen. Für den 30. April hätte sie bis 31. Oktober des Vorjahres eingehen müssen — verpasst. Für den 31. Oktober dieses Jahres genügt der Eingang bis 30. April. Heute (20. März) ist dies rechtzeitig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: 31. Oktober — Kündigung rechtzeitig bis 30. April möglich.' }, { feld: 'optionen', id: 'opt-1', text: '20. September ist kein ordentlicher Kündigungstermin — Monatsende nötig.' }, { feld: 'optionen', id: 'opt-2', text: 'Der 30. April ist verpasst — Kündigung hätte 6 Monate vorher eingehen müssen.' }, { feld: 'optionen', id: 'opt-3', text: '30. April nächstes Jahr ist zu spät — der 31. Oktober ist noch erreichbar.' } ] },
  { id: '7f557150-3764-4bfc-98a5-ae906e2886d4', fachbereich: 'Recht', musterlosung: 'Art. 28 ZGB kennt drei Rechtfertigungsgründe für eine Persönlichkeitsverletzung: Einwilligung der verletzten Person, überwiegendes privates oder öffentliches Interesse (z.B. Presseberichterstattung) und Gesetz. Unwissenheit des Verletzers ist kein Rechtfertigungsgrund — die Widerrechtlichkeit wird objektiv bestimmt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Einwilligung des Verletzten macht die Verletzung rechtmässig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Überwiegendes Interesse (z.B. Pressefreiheit vs. Persönlichkeit).' }, { feld: 'optionen', id: 'opt-2', text: 'Unwissenheit ist kein Rechtfertigungsgrund — objektive Widerrechtlichkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gesetzliche Erlaubnis (z.B. amtliche Anordnung).' } ] },
  { id: '7fcfafb4-24ac-4112-99ef-0af660e2aee4', fachbereich: 'Recht', musterlosung: 'Die sachliche Zuständigkeit bestimmt, welche Art von Gericht für einen Fall zuständig ist — insbesondere ob ein Einzelrichter (vereinfachtes Verfahren) oder ein Kollegialgericht (ordentliches Verfahren) urteilt. Die örtliche Zuständigkeit bestimmt dagegen den Ort des Verfahrens.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Der Ort ist die örtliche Zuständigkeit — nicht die sachliche.' }, { feld: 'optionen', id: 'opt-1', text: 'Zivil/strafrechtlich ist eine andere Unterscheidung — materielles Recht.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Anwaltswahl ist unabhängig von der Zuständigkeit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Art des Gerichts (Einzelrichter oder Kollegialgericht).' } ] },
  { id: '80052af2-d07c-4db5-a492-6fc371a42c30', fachbereich: 'Recht', musterlosung: 'Die Frau ist mittelbare Täterin: Sie hat die Tat nicht selbst ausgeführt, sondern ihren geisteskranken Bruder als «Werkzeug» benutzt, da dieser die Tragweite seines Handelns nicht erkennen konnte. Die mittelbare Täterin wird bestraft, als hätte sie die Tat selbst ausgeführt. Unterschied zur Anstiftung: Dort fasst der Ausführende einen eigenen Tatentschluss.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht straffrei — mittelbare Täterschaft ist eigene Strafbarkeit.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Gehilfenschaft — sie war die treibende Kraft, nicht nur Helferin.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Mittelbare Täterin — Bruder als «Werkzeug» instrumentalisiert.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Anstiftung — der Bruder fasste keinen eigenen Tatentschluss.' } ] },
  { id: '801b4d8c-8686-4a25-919b-8b975a260895', fachbereich: 'Recht', musterlosung: 'Kernmerkmal des Arbeitsvertrags (OR 319) ist die Unterordnung des Arbeitnehmers unter Weisung und Kontrolle des Arbeitgebers. Der Arbeitnehmer erbringt unselbstständige, entgeltliche Arbeit während bestimmter oder unbestimmter Zeit. Die Subordination unterscheidet den Arbeitsvertrag vom Auftrag und Werkvertrag.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Selbstbestimmung der Arbeitszeiten widerspricht der Unterordnung — typisch für Auftragsverhältnisse.' }, { feld: 'optionen', id: 'opt-1', text: 'Der AG trägt das Unternehmensrisiko — nicht der AN.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Unterordnung unter Weisung und Kontrolle (OR 319).' }, { feld: 'optionen', id: 'opt-3', text: 'Selbstständigkeit ist Auftrags- oder Werkvertragsmerkmal — nicht Arbeitsvertrag.' } ] },
  { id: '80f0e971-2d43-4011-b656-0a45394d6cc1', fachbereich: 'Recht', musterlosung: 'Arbeitsverträge können auch mündlich oder konkludent zustande kommen (OR 320 Abs. 2). Es gilt Formfreiheit — entscheidend ist die übereinstimmende Willenserklärung (OR 1). Der Arbeitgeber hat allerdings nach OR 330b eine Informationspflicht: Er muss die wesentlichen Vertragsbedingungen schriftlich mitteilen. Eine Verletzung dieser Pflicht führt aber nicht zur Unwirksamkeit des Vertrags.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Mündlicher Konsens genügt — Formfreiheit (OR 320 Abs. 2).' }, { feld: 'optionen', id: 'opt-1', text: 'Die 7-Tage-Bestätigung ist kein Gültigkeitserfordernis.' }, { feld: 'optionen', id: 'opt-2', text: 'Informationspflicht-Verletzung macht den Vertrag nicht unwirksam.' }, { feld: 'optionen', id: 'opt-3', text: 'Schriftlichkeit ist nicht Voraussetzung — Formfreiheit.' } ] },
  { id: '811f6f9f-e705-4c99-ba4e-12bc84316606', fachbereich: 'Recht', musterlosung: 'Die polizeiliche Generalklausel erlaubt Grundrechtseinschränkungen bei ernster, unmittelbarer und nicht anders abwendbarer Gefahr — auch ohne spezifische gesetzliche Grundlage. Ein Erdbeben mit Einsturzgefahr ist ein klassisches Beispiel: Die Räumung greift in persönliche Freiheit und Eigentum ein, ist aber wegen der akuten Gefahr gerechtfertigt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Parlamentarisches Gesetzgeben ist ordentliche gesetzliche Grundlage — kein Beispiel für Generalklausel.' }, { feld: 'optionen', id: 'opt-1', text: 'Gerichtliche Verurteilung folgt dem ordentlichen Weg — nicht Generalklausel.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Akute Gefahr ohne spezifisches Gesetz rechtfertigt polizeiliches Handeln.' }, { feld: 'optionen', id: 'opt-3', text: 'Routinekontrollen erfordern gesetzliche Grundlage — nicht Generalklausel.' } ] },
  { id: '814089d3-dcef-4a1a-88ff-bfb79d82c15b', fachbereich: 'Recht', musterlosung: 'Art. 259a OR gilt, wenn drei Voraussetzungen erfüllt sind: Mangel nicht vom Mieter verschuldet, nicht durch gewöhnlichen Unterhalt behebbar, Mieter wird im Gebrauch gestört. Ein tropfendes Dach oder eine defekte Wasserleitung erfordert einen Fachmann und stört erheblich. Der Mieter kann Mängelbeseitigung, Mietzinsreduktion und Schadenersatz verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein gewöhnlicher Unterhalt — Wasserschaden braucht Fachmann.' }, { feld: 'optionen', id: 'opt-1', text: 'Doch — Mietrecht regelt sehr wohl Wasserschäden an der Mietsache.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 259 und 259a sind alternativ — nicht kumulativ anwendbar.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Art. 259a OR — kein Mieter-Verschulden, kein gewöhnlicher Unterhalt, Gebrauchsstörung.' } ] },
  { id: '82bc8a33-539e-4cf7-a4cb-24562951ccb2', fachbereich: 'Recht', musterlosung: 'Eine Obligation ist ein Schuldverhältnis: Der Schuldner ist verpflichtet, eine Leistung zu erbringen; der Gläubiger hat ein Forderungsrecht darauf. Obligationen entstehen aus Vertrag, unerlaubter Handlung oder ungerechtfertigter Bereicherung (Art. 1, 41, 62 OR). Sie wirken nur inter partes (relative Rechte).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Eigentum ist ein dingliches Recht — nicht eine Obligation.' }, { feld: 'optionen', id: 'opt-1', text: 'Obligation ist allgemeiner Begriff — nicht auf Grundstückskauf beschränkt.' }, { feld: 'optionen', id: 'opt-2', text: 'Strafrechtliche Verpflichtungen folgen aus Strafrecht, nicht OR.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Schuldner leistet, Gläubiger fordert — klassisches Schuldverhältnis.' } ] },
  { id: '82d5ce9e-309e-43e1-8977-90aeed4615ad', fachbereich: 'Recht', musterlosung: 'Die Zustimmung des gesetzlichen Vertreters kann ausdrücklich oder stillschweigend erfolgen. Stillschweigende Zustimmung liegt vor, wenn der gesetzliche Vertreter von der Handlung weiss und nicht widerspricht. Beispiel: Die Mutter sieht, wie ihr 16-jähriger Sohn ein Töffli kauft, und sagt nichts. Schweigen = Zustimmung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Notar ist nicht erforderlich — formfreie Zustimmung möglich.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine automatische 30-Tage-Frist — es geht um tatsächliches Wissen und Schweigen.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftform ist nicht nötig — stillschweigend bedeutet formlos.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Schweigen mit Kenntnis der Handlung gilt als Zustimmung.' } ] },
  { id: '82f10671-b7dd-4ea1-bdd8-67d177052a36', fachbereich: 'Recht', musterlosung: 'Nach Art. 3 Abs. 1 ZGB wird der gute Glaube vermutet. Der Agent muss seine Gutgläubigkeit nicht beweisen — die Arbeitgeberin müsste den bösen Glauben beweisen (Kenntnis vom Prokuraentzug). Diese Vermutung zum guten Glauben führt zur Beweislastumkehr.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die fehlende SHAB-Publikation ist für die Beweislast nicht entscheidend — die Vermutung.' }, { feld: 'optionen', id: 'opt-1', text: 'Bei HR-Einträgen gelten nicht andere Regeln — Art. 3 ZGB gilt weiter.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht der Kläger (= Agent) trägt die Beweislast — die Vermutung kehrt sie um.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Gutglaubensvermutung nach Art. 3 Abs. 1 ZGB.' } ] },
  { id: '83ee5fcb-e39e-4ccc-8171-018c3a0dafff', fachbereich: 'Recht', musterlosung: 'Nach Art. 61 StGB kann ein junger Erwachsener (18–25 Jahre) in eine spezielle Einrichtung eingewiesen werden, wenn drei Voraussetzungen kumulativ vorliegen: erhebliche Persönlichkeitsstörung, Zusammenhang zwischen Störung und Tat sowie Chance, dass er künftig keine weiteren Straftaten begeht. Ziel ist die Vermittlung von Fähigkeiten für ein straffreies Leben.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kein Antragserfordernis — Massnahmen werden vom Gericht angeordnet.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht bei jedem Vergehen — die Voraussetzungen sind restriktiv.' }, { feld: 'optionen', id: 'opt-2', text: 'Schweregrad allein reicht nicht — Persönlichkeitsstörung + Zusammenhang nötig.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Persönlichkeitsstörung + Zusammenhang + Resozialisierungschance.' } ] },
  { id: '841b82cf-342f-4b60-9f22-dd25bb108930', fachbereich: 'Recht', musterlosung: 'Der Teppich ist gestohlen, also dem Eigentümer abhanden gekommen (Art. 934 ZGB). Die 5-Jahres-Frist beginnt mit dem Diebstahl — bei 5½ Jahren ist sie formal abgelaufen. Da Frau Tobler den Teppich jedoch bei einem Kaufmann erworben hat, der mit Waren der gleichen Art handelt, muss sie ihn nach Art. 934 Abs. 2 ZGB nur gegen Vergütung des bezahlten Preises (CHF 4\'000) herausgeben.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht entschädigungslos — Art. 934 Abs. 2 sieht Kaufpreiserstattung vor.' }, { feld: 'optionen', id: 'opt-1', text: 'Die 5-Jahres-Frist betrifft die normale Herausgabe — Kaufmann-Regel gilt weiter.' }, { feld: 'optionen', id: 'opt-2', text: 'Erwerb beim Kaufmann befreit nicht — nur von der entschädigungslosen Rückgabe.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Herausgabe gegen Erstattung der CHF 4\'000 (Art. 934 Abs. 2 ZGB).' } ] },
  { id: '85230b1f-19dc-42a7-ade7-b3506a8326e1', fachbereich: 'Recht', musterlosung: 'Beide Parteien gingen von der Echtheit des Gemäldes aus — eine gemeinsame Vorstellung über eine wesentliche Vertragsgrundlage. Es liegt ein Grundlagenirrtum nach OR 24 Abs. 1 Ziff. 4 vor. Da auch der Verkäufer getäuscht wurde, liegt keine absichtliche Täuschung vor. Lisa kann den Vertrag anfechten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine absichtliche Täuschung — auch der Verkäufer war getäuscht.' }, { feld: 'optionen', id: 'opt-1', text: 'Kein Erklärungsirrtum — beide wollten genau dieses Gemälde (als Echt-Monet).' }, { feld: 'optionen', id: 'opt-2', text: 'Übervorteilung verlangt Missverhältnis + Ausnutzung einer Schwäche — nicht erfüllt.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Grundlagenirrtum (OR 24 Abs. 1 Ziff. 4) — gemeinsame Fehlvorstellung.' } ] },
  { id: '853b8a53-0848-4f5c-ac0b-b2037020e775', fachbereich: 'Recht', musterlosung: 'Die Persönlichkeit wird in drei Sphären unterteilt: Gemeinsphäre (öffentliches Auftreten, z.B. Strasse, öffentliche Rede), Privatsphäre (engerer persönlicher Bereich, z.B. Familie zu Hause, Freundeskreis) und Intimsphäre (innerster Bereich, z.B. Duschen, Sexualität). Ein Familien-Abendessen zu Hause gehört zur Privatsphäre.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Spaziergang auf der Strasse = Gemeinsphäre.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Familienessen zu Hause = Privatsphäre.' }, { feld: 'optionen', id: 'opt-2', text: 'Öffentliche Rede = Gemeinsphäre.' }, { feld: 'optionen', id: 'opt-3', text: 'Duschen = Intimsphäre (höchster Schutz).' } ] },
  { id: '85429791-a5c5-484c-8780-8ecdcd508957', fachbereich: 'Recht', musterlosung: 'Die Unterscheidung zwischen Rechtssubjekten und Rechtsobjekten ist fundamental: Nur Rechtssubjekte (natürliche und juristische Personen) können Träger von Rechten und Pflichten sein, Verträge schliessen, klagen und verklagt werden. Rechtsobjekte sind Gegenstände des Rechtsverkehrs — Sachen und Rechte, über die verfügt wird.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nur Rechtssubjekte sind Träger von Rechten und Pflichten.' }, { feld: 'optionen', id: 'opt-1', text: 'Rechtsobjekte haben keinen höheren Schutz — sie sind selbst Gegenstand des Schutzes.' }, { feld: 'optionen', id: 'opt-2', text: 'Rechtsobjekte können nicht klagen — sie sind Gegenstand, nicht Handelnder.' }, { feld: 'optionen', id: 'opt-3', text: 'Die Unterscheidung gilt im gesamten Zivilrecht — nicht nur Strafrecht.' } ] },
  { id: '858a4384-0211-4701-86cd-43956c3babc7', fachbereich: 'Recht', musterlosung: 'Der Kerngehalt nach Art. 36 Abs. 4 BV darf unter keinen Umständen angetastet werden. Zum Kerngehalt der persönlichen Freiheit (Art. 10 BV) gehört insbesondere das Folterverbot und das Verbot grausamer, unmenschlicher oder erniedrigender Behandlung. Dieses Verbot gilt absolut — auch in Krisenzeiten.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Reisefreiheit ist einschränkbar (z.B. bei Ausschaffung) — nicht Kerngehalt.' }, { feld: 'optionen', id: 'opt-1', text: 'Das Recht auf ein Auto existiert nicht — keine Grundrechtsdimension.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Folterverbot + Verbot grausamer Behandlung = absoluter Kerngehalt.' }, { feld: 'optionen', id: 'opt-3', text: 'Arbeitszwang ist besonderer Eingriff — Recht auf Arbeitslosigkeit kein Grundrecht.' } ] },
  { id: '85e80eb0-4974-4bd3-981f-1f228b826489', fachbereich: 'Recht', musterlosung: 'Eigentum kann auf drei Arten verloren gehen: durch Rechtsübertragung auf einen neuen Eigentümer (Kauf, Schenkung, Enteignung), durch Dereliktion (Aufgabe ohne Übertragung, z.B. Sachwegwerfen) oder durch Untergang der Sache (Zerstörung, Verbrauch). Mehrere Wege existieren also — nicht nur der Verkauf.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Rechtsübertragung, Dereliktion oder Untergang als Verlustgründe.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur Gerichtsurteil — auch Rechtsgeschäfte führen zum Verlust.' }, { feld: 'optionen', id: 'opt-2', text: 'Nicht nur Verkauf — auch Schenkung, Untergang, Dereliktion.' }, { feld: 'optionen', id: 'opt-3', text: 'Eigentum kann sehr wohl verloren gehen — mehrere Wege.' } ] },
  { id: '860c064c-a132-4fd2-b43d-e1d837d47643', fachbereich: 'Recht', musterlosung: 'Übertretungen werden nach Art. 103 StGB mit Busse bestraft. Die Bussenhöhe beträgt CHF 1 bis CHF 10\'000 (Art. 106 Abs. 1 StGB). Bei Nichtzahlung kann eine Ersatzfreiheitsstrafe von 1 Tag bis 3 Monaten ausgesprochen werden (Art. 106 Abs. 2 StGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Freiheitsstrafen gelten für Verbrechen (über 3 Jahre) — nicht für Übertretungen.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Busse nach Art. 103, Art. 106 StGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Gemeinnützige Arbeit bei Vergehen — nicht bei Übertretungen.' }, { feld: 'optionen', id: 'opt-3', text: 'Geldstrafe in Tagessätzen ist für Vergehen — nicht für Übertretungen.' } ] },
  { id: '86fe5701-3bb9-4079-8388-63c3257c77b5', fachbereich: 'Recht', musterlosung: 'Ein Pfandrecht ist ein beschränktes dingliches Recht zur Sicherung einer Forderung. Der Pfandgläubiger hat das Recht, bei Nichterfüllung der Forderung den Pfandgegenstand verwerten zu lassen und sich aus dem Erlös vorweg zu befriedigen. Pfandrechte können beweglich (Faustpfand) oder unbeweglich (Grundpfand) sein.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Vermietung ist Obligationsrecht — nicht dingliche Sicherung.' }, { feld: 'optionen', id: 'opt-1', text: 'Das wäre Nachbarrecht oder Dienstbarkeit — nicht Pfand.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Sicherung der Forderung — Verwertung bei Nichterfüllung.' }, { feld: 'optionen', id: 'opt-3', text: 'Eigentum geht beim Pfandrecht nicht über — bleibt beim Verpfänder.' } ] },
  { id: '879520ee-a447-450d-9aec-5fcc568bf192', fachbereich: 'Recht', musterlosung: 'Nach OR 74 Abs. 2 gibt es drei Erfüllungsorte je nach Schuldart: Geldschulden sind Bringschulden zum Gläubiger (Ziff. 1). Speziesschulden (individuell bestimmte Sachen) sind Holschulden am Standort der Sache (Ziff. 2). Gattungsschulden werden am Wohnsitz des Schuldners erfüllt (Ziff. 3). Der Grundsatz: Geld zum Gläubiger, Gattung beim Schuldner, Spezies am Standort.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Geldschulden = Bringschuld zum Gläubiger (OR 74 Abs. 2 Ziff. 1).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Speziesschuld = Holschuld am Standort der Sache (OR 74 Abs. 2 Ziff. 2).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Gattungsschuld = Wohnsitz des Schuldners (OR 74 Abs. 2 Ziff. 3).' }, { feld: 'optionen', id: 'opt-3', text: 'Falsch — Geldschulden sind Bringschulden zum Gläubiger, nicht zum Schuldner.' } ] },
  { id: '87a39828-14a9-4a34-a5b3-6f71aea7a340', fachbereich: 'Recht', musterlosung: 'Realsicherheiten sind Sicherungen an einer Sache: Kaution (hinterlegter Geldbetrag), Retentionsrecht (OR 895), Pfandrechte (Fahrnispfand ZGB 884, Grundpfand ZGB 836) und Eigentumsvorbehalt (ZGB 715). Die Konventionalstrafe ist dagegen eine Personalsicherheit — sie verpflichtet den Schuldner zu einer zusätzlichen Leistung bei Nichterfüllung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Kaution ist Realsicherheit — gebundener Geldbetrag.' }, { feld: 'optionen', id: 'opt-1', text: 'Konventionalstrafe ist Personalsicherheit — Leistungsversprechen des Schuldners.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Pfandrechte (Fahrnis- und Grundpfand) sind klassische Realsicherheiten.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Eigentumsvorbehalt ist Realsicherheit — Eigentum bleibt bis Zahlung.' } ] },
  { id: '87eced19-c531-4049-b4e9-82d7aab4191c', fachbereich: 'Recht', musterlosung: 'Art. 257f OR regelt die Sorgfalt- und Rücksichtnahmepflicht des Mieters: Er muss die Mietsache sorgfältig gebrauchen und auf Hausbewohner und Nachbarn Rücksicht nehmen. Bei schwerwiegenden Verstössen kann der Vermieter nach Abmahnung fristlos oder ordentlich kündigen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Art. 257f OR — Sorgfalt und Rücksichtnahme.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 253 OR definiert den Mietvertrag allgemein.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 262 OR regelt die Untermiete.' }, { feld: 'optionen', id: 'opt-3', text: 'Art. 270 OR regelt die Mietzinsanfechtung.' } ] },
  { id: '887b5afc-bc85-44a3-ac47-040d12c966c7', fachbereich: 'Recht', musterlosung: 'Eine einmal erteilte Einwilligung zur Tierhaltung — auch eine stillschweigende — darf nicht ohne triftigen Grund widerrufen werden. Frau Neckermann hat die Katze über längere Zeit geduldet und sogar gestreichelt. Dieses Verhalten begründet eine stillschweigende Einwilligung. Sie kann die Beseitigung daher nicht mehr verlangen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine 6-Monats-Frist — die stillschweigende Einwilligung steht entgegen.' }, { feld: 'optionen', id: 'opt-1', text: 'Katzen können vertraglich verboten werden — es geht hier um die stillschweigende Einwilligung.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Vermieterin ist an ihre (stillschweigende) Einwilligung gebunden.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Stillschweigende Einwilligung durch längere Duldung und Streicheln.' } ] },
  { id: '8aa7009f-79c4-4b8b-b4c6-6aae043b0d08', fachbereich: 'Recht', musterlosung: 'Es handelt sich um Zufall (Art. 12 Abs. 1 i.V.m. Abs. 3 StGB): Der Taterfolg tritt ein, ohne dass dem Täter ein Vorwurf gemacht werden kann. Er handelte nicht vorsätzlich, und eine Sorgfaltspflichtverletzung ist nicht erkennbar — auf einer übersichtlichen Wiese ist nicht mit plötzlich erscheinenden Drohnen zu rechnen. Rechtsfolge: Straffreiheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zufall — kein Vorwurf, keine vorhersehbare Gefahr.' }, { feld: 'optionen', id: 'opt-1', text: 'Keine Sorgfaltspflichtverletzung — Drohnen in übersichtlicher Wiese sind nicht vorhersehbar.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Vorsatz — niemand wollte die Drohne treffen.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine generelle Vorhersehbarkeit von Drohnenschäden beim Steinewerfen.' } ] },
  { id: '8b6949a7-1efa-43e9-98d3-6b28afa07ff1', fachbereich: 'Recht', musterlosung: 'Nach Art. 264 Abs. 1 OR kann der Mieter vorzeitig aus dem Vertrag aussteigen, wenn er einen zumutbaren, zahlungsfähigen Nachmieter vorschlägt, der bereit ist, den Vertrag zu den gleichen Bedingungen zu übernehmen. Diskriminierungsmerkmale wie Geschlecht oder Herkunft sind irrelevant — der Vermieter darf sie nicht als Ablehnungsgrund anführen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Zumutbarkeit ist die erste Voraussetzung (Art. 264 OR).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Zahlungsfähigkeit schützt den Vermieter vor Ausfallrisiko.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Übernahme zu gleichen Bedingungen sichert die ursprüngliche Vertragslage.' }, { feld: 'optionen', id: 'opt-3', text: 'Geschlechts-Kriterium wäre diskriminierend und unzulässig.' } ] },
  { id: '8bad5592-618c-4978-8c2a-d28b99bffde4', fachbereich: 'Recht', musterlosung: 'Die Bürgschaft erfordert nach OR 493 schriftliche Form mit Angabe des Höchstbetrags. Der Bürge haftet nur bis zu diesem Betrag (OR 499). Bei der Solidarbürgschaft (OR 496) kann der Bürge bereits nach Mahnung des Hauptschuldners belangt werden — ohne vorherige Betreibung. Die Formvorschrift gilt auch für die Konventionalstrafe als Nebenabrede.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Schriftform + Höchstbetrag zwingend (OR 493).' }, { feld: 'optionen', id: 'opt-1', text: 'Falsch — Bürge haftet nur bis zum Höchstbetrag (OR 499).' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Solidarbürgschaft nach OR 496 erlaubt direkte Inanspruchnahme nach Mahnung.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Formvorschrift erfasst auch Nebenabreden wie Konventionalstrafe.' } ] },
  { id: '8bc8c6c8-e325-45f7-be0c-0dc10c29c60a', fachbereich: 'Recht', musterlosung: 'Die Unschuldsvermutung (Art. 6 Ziff. 2 EMRK, Art. 10 StPO) ist ein fundamentaler Grundsatz des Rechtsstaats. Sie schützt den Einzelnen vor willkürlicher Bestrafung, indem sie die Beweislast der Staatsanwaltschaft zuweist und den Beschuldigten nicht zwingt, seine Unschuld zu beweisen. Ohne Unschuldsvermutung wäre staatliche Willkür möglich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Die Polizei darf weiter ermitteln — die Unschuldsvermutung schliesst das nicht aus.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht alle werden freigesprochen — Schuldbeweis ist möglich.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Schutz vor Willkür + Beweislast bei Anklagebehörde.' }, { feld: 'optionen', id: 'opt-3', text: 'Verteidigerzugang ist anderes Recht (Art. 32 BV) — nicht Unschuldsvermutung.' } ] },
  { id: '8cdc1a69-2fc0-4bf1-8e1f-789ff79cb445', fachbereich: 'Recht', musterlosung: 'Rechtssubjekte sind Träger von Rechten und Pflichten — natürliche Personen (Menschen) und juristische Personen (AG, GmbH, Verein, Stiftung). Grundstücke, Autos, Bankkonten, Patente und Goldbarren sind Rechtsobjekte — Gegenstände, über die Rechtssubjekte verfügen. Nur Rechtssubjekte können klagen, verklagt werden und Verträge schliessen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Mensch = natürliche Person, AG = juristische Person. Beide Rechtssubjekte.' }, { feld: 'optionen', id: 'opt-1', text: 'Geld und Gold sind Rechtsobjekte — Sachen ohne Trägerschaft.' }, { feld: 'optionen', id: 'opt-2', text: 'Grundstück und Auto sind Rechtsobjekte — nicht Trägerschaft von Rechten.' }, { feld: 'optionen', id: 'opt-3', text: 'Bankkonto und Patent sind Rechtsobjekte — forderungsrechtliche bzw. Immaterialgüter.' } ] },
  { id: '8e89db58-8a85-49e0-b736-a40b04dcd89d', fachbereich: 'Recht', musterlosung: 'Professor Niggli argumentiert, dass härtere Strafen allein die Menschen nicht von Gesetzesverstössen abhalten. Mehr Sicherheit setze höhere Kontrolldichte voraus — also mehr Polizeipräsenz, was teuer sei. Die Abschreckungswirkung harter Strafen sei begrenzt; die Gesellschaft solle primär auf Resozialisierung setzen, um künftige Straftaten zu verhindern.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht die Rationalität der Menschen — die Abschreckungswirkung ist Nigglis Punkt.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht Vergeltung — Niggli argumentiert gegen rein repressive Ansätze.' }, { feld: 'optionen', id: 'opt-2', text: 'Drill-Lager-System ist nicht Nigglis Argument — im Gegenteil.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Begrenzte Abschreckungswirkung + Kontrolldichte als Sicherheitsfaktor.' } ] },
  { id: '8e92840b-d365-4d9c-b8cc-cf4b7b2d37f8', fachbereich: 'Recht', musterlosung: 'Nicht jeder Rechtsgrundsatz steht im ZGB. Das Gebot von Treu und Glauben ist in Art. 2 Abs. 1 ZGB verankert. Die Regel «Bundesrecht bricht kantonales Recht» steht in Art. 49 BV. «Unwissenheit schützt vor Strafe nicht» ist in Art. 21 StGB. «Lex posterior» ist ein ungeschriebener allgemeiner Rechtsgrundsatz ohne spezifische Norm.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Ist im ZGB verankert (Art. 2 Abs. 1 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Art. 49 BV — nicht im ZGB.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Art. 21 StGB — nicht im ZGB.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Ungeschriebener allgemeiner Rechtsgrundsatz — nicht im ZGB.' } ] },
  { id: '8eff9c58-2e81-4c8b-b406-4985b49e54bf', fachbereich: 'Recht', musterlosung: 'Antragsdelikte sind daran erkennbar, dass der Straftatbestand im besonderen Teil des StGB den Wortlaut «wird auf Antrag bestraft» enthält (Art. 30 StGB). Fehlt dieser Zusatz, handelt es sich um ein Offizialdelikt — die Staatsanwaltschaft verfolgt von Amtes wegen. Ein ausdrücklicher Hinweis auf Offizialdelikt ist gerade nicht nötig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '«Von Amtes wegen» wird nicht erwähnt — das ist der Normalfall.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: «Wird auf Antrag bestraft» markiert Antragsdelikte.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Hinweise im allgemeinen Teil — nur im spezifischen Tatbestand.' }, { feld: 'optionen', id: 'opt-3', text: 'Strafhöhe ist nicht entscheidend — auch Vergehen können Antragsdelikte sein.' } ] },
  { id: '8f919e5a-dadb-4fd6-b61c-9db8fd46dc2e', fachbereich: 'Recht', musterlosung: 'Nach OR 321a muss der Arbeitnehmer seine Arbeit mit der Sorgfalt eines gewissenhaften Arbeiters ausführen und die berechtigten Interessen des Arbeitgebers treu wahren. Die Sorgfalts- und Treuepflicht ist zentral und kann bei Verletzung zu Haftung führen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Überstunden müssen kompensiert oder entschädigt werden — nicht gratis.' }, { feld: 'optionen', id: 'opt-1', text: 'Pausen sind gesetzlich zwingend (Art. 15 ArG) — keine Umgehung erlaubt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Sorgfalt und Treue als zentrale AN-Pflicht (OR 321a).' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Maximalpflicht — nur die eines gewissenhaften Arbeiters.' } ] },
  { id: '9167f627-845e-4a58-847e-d38ae25d2478', fachbereich: 'Recht', musterlosung: 'Nach Art. 86 Abs. 1 StGB ist eine bedingte Entlassung nach 2/3 der Strafe möglich (mindestens 3 Monate). 2/3 von 6 Jahren = 4 Jahre. Voraussetzung ist ein gutes Verhalten im Strafvollzug und die Annahme, dass keine weiteren Straftaten zu erwarten sind. Claudia erfüllt diese Voraussetzungen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: 4 Jahre = 2/3 von 6 Jahren (Art. 86 Abs. 1 StGB).' }, { feld: 'optionen', id: 'opt-1', text: '5 Jahre wären zu viel — nicht 2/3 der Strafe.' }, { feld: 'optionen', id: 'opt-2', text: '3 Jahre wären die Hälfte — das Gesetz verlangt 2/3.' }, { feld: 'optionen', id: 'opt-3', text: 'Bei Strafen über 5 Jahre ist bedingte Entlassung möglich — das Gesetz kennt keine solche Grenze.' } ] },
  { id: '91afe581-6c02-4491-9858-d0f3a4ef204f', fachbereich: 'Recht', musterlosung: 'Bei der Art. 36 BV-Prüfung zum Kopftuchverbot ist die Verhältnismässigkeit der umstrittenste Punkt. Die Frage ist, ob ein Verbot nur im Unterricht ein geeignetes und zumutbares Mittel ist — gegenüber einem generellen Berufsverbot ist es milder, aber ob auch im Unterricht das Kopftuch stört, ist diskutabel. Der EGMR hat das Verbot in Dahlab vs. Schweiz als verhältnismässig beurteilt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Das öffentliche Interesse (religiöse Neutralität) ist in der Schweiz anerkannt.' }, { feld: 'optionen', id: 'opt-1', text: 'Der Kerngehalt bleibt gewahrt — Glauben kann ausserhalb der Schule gelebt werden.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verhältnismässigkeit ist die zentrale Streitfrage.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Schulgesetz bildet die gesetzliche Grundlage — unstrittig.' } ] },
  { id: '91ccf867-9095-4c6a-aff5-4753a179159b', fachbereich: 'Recht', musterlosung: 'Einfache Kausalhaftungen bestehen ohne Verschulden des Haftpflichtigen: Geschäftsherr (OR 55), Tierhalter (OR 56), Familienoberhaupt (ZGB 333) und Werkeigentümer (OR 58). Die Motorfahrzeughaftung ist dagegen eine Gefährdungshaftung (scharfe Kausalhaftung) — härter wegen des besonderen Gefahrenpotenzials.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Vertragshaftung setzt Vertrag voraus — andere Kategorie.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Tierhalter (OR 56) ist klassische einfache Kausalhaftung.' }, { feld: 'optionen', id: 'opt-2', text: 'Motorfahrzeughaftung ist Gefährdungshaftung — nicht einfache Kausalhaftung.' }, { feld: 'optionen', id: 'opt-3', text: 'Vorsätzliche Körperverletzung ist Verschuldenshaftung (OR 41) — nicht kausal.' } ] },
  { id: '91d79e17-7ee7-4283-a8b5-c7cfe58663fd', fachbereich: 'Recht', musterlosung: 'Beim Schuldbrief (Art. 842 ff. ZGB) sind Forderung und Grundpfandrecht zu einer Einheit verbunden. Der Schuldbrief kann als Wertpapier übertragen werden — Register-Schuldbrief oder Papier-Schuldbrief. Bei der Grundpfandverschreibung (Art. 824 ff. ZGB) dient das Grundpfand nur als akzessorische Sicherheit für eine Forderung, ohne eigene Wertpapierqualität.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kosten sind nicht das Unterscheidungskriterium — Rechtsstruktur zählt.' }, { feld: 'optionen', id: 'opt-1', text: 'Es gibt klare rechtliche Unterschiede — unterschiedliche Kategorien.' }, { feld: 'optionen', id: 'opt-2', text: 'Beide können verschiedene Forderungen sichern — nicht nur Darlehen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Schuldbrief = Einheit Forderung + Pfand als Wertpapier; Grundpfandverschreibung = akzessorische Sicherheit.' } ] },
  { id: '91f8c682-9c2a-4bcb-91a4-6ac86537d6b7', fachbereich: 'Recht', musterlosung: 'Die Gefährdungshaftung (scharfe Kausalhaftung) trifft den Halter von Vorrichtungen oder Sachen mit besonderem Gefahrenpotenzial — z.B. Motorfahrzeuge, Atomanlagen, Eisenbahn, Rohrleitungen. Eine Entlastung ist nur bei grobem Drittverschulden, höherer Gewalt oder grobem Selbstverschulden möglich — strenger als bei einfacher Kausalhaftung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Einfache Kausalhaftung betrifft mehrere Kategorien — nicht nur Fahrzeuge.' }, { feld: 'optionen', id: 'opt-1', text: 'Es gibt einen klaren Unterschied — Entlastungsmöglichkeiten und Gefahrenpotenzial.' }, { feld: 'optionen', id: 'opt-2', text: 'Gefährdungshaftung ist verschuldensunabhängig — das ist ihr Wesen.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Besonders gefährliche Vorrichtungen/Sachen — strenger als einfache Kausalhaftung.' } ] },
  { id: '922c59ad-7bf6-4ba1-8d51-d85a5bb0b2be', fachbereich: 'Recht', musterlosung: 'Nach Art. 14 ZGB ist mündig (volljährig), wer das 18. Lebensjahr zurückgelegt hat. Die Mündigkeit ist eine der beiden Voraussetzungen der Handlungsfähigkeit (Art. 13 ZGB); die andere ist die Urteilsfähigkeit. Beide müssen vorliegen, damit eine Person selbstständig Rechtsgeschäfte abschliessen kann.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '20 Jahre gelten nicht — Mündigkeit mit 18 (Art. 14 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: 18 Jahre nach Art. 14 ZGB.' }, { feld: 'optionen', id: 'opt-2', text: '16 Jahre wären ehefähig (aufgehoben seit 2013) — nicht mündig.' }, { feld: 'optionen', id: 'opt-3', text: '14 Jahre ist strafmündig — nicht zivilrechtlich mündig.' } ] },
  { id: '930bddbb-c5a5-4972-ad9d-2c53e9ca15f3', fachbereich: 'Recht', musterlosung: 'Die Persönlichkeit ist nach dem Sphärenmodell gestuft: Gemeinsphäre (öffentliches Auftreten, geringster Schutz), Privatsphäre (persönlicher Bereich, mittlerer Schutz), Intimsphäre (innerster Bereich, stärkster Schutz). Je tiefer der Eingriff in den Kern der Persönlichkeit, desto schwerer wiegt die Verletzung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Privatsphäre ist mittlerer Schutz — nicht stärkster.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Intimsphäre = innerster Kern der Persönlichkeit.' }, { feld: 'optionen', id: 'opt-2', text: 'Die Sphären sind gerade nicht gleich — abgestufter Schutz.' }, { feld: 'optionen', id: 'opt-3', text: 'Gemeinsphäre ist am wenigsten geschützt — öffentliches Auftreten.' } ] },
  { id: '933ca4a5-6569-4985-9033-ab1b8b28e250', fachbereich: 'Recht', musterlosung: 'Nach Art. 269d OR muss eine Mietzinserhöhung auf dem vom Kanton genehmigten Formular mitgeteilt und begründet werden. Ein einfacher Brief genügt nicht. Die Formvorschrift ist zwingend — bei Verletzung ist die Mietzinserhöhung nichtig. Der Mieter muss die ursprüngliche Miete weiterzahlen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Formnichtigkeit ist nicht von Widerspruch abhängig — die Erhöhung ist ex lege unwirksam.' }, { feld: 'optionen', id: 'opt-1', text: 'Erhöhungen sind unter den Form- und Begründungsvoraussetzungen zulässig — nicht generell verboten.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Formular + Begründung zwingend (Art. 269d OR).' }, { feld: 'optionen', id: 'opt-3', text: 'Brief genügt nicht — amtliches Formular erforderlich.' } ] },
  { id: '93857854-6832-407e-b375-6ca585068d2a', fachbereich: 'Recht', musterlosung: 'Nichtigkeit bedeutet Unwirksamkeit ab initio — der Vertrag entfaltet nie Wirkung (z.B. bei Verstoss gegen gute Sitten oder Formvorschriften). Anfechtbarkeit bedeutet, dass der Vertrag gültig bleibt, bis er vom Geschädigten angefochten wird (z.B. bei Willensmängeln). Nichtigkeit tritt ein bei fehlenden Vertragsvoraussetzungen, Anfechtbarkeit bei Willensmängeln.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Nichtigkeit = keine Wirkung ab initio.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Anfechtbarer Vertrag gültig bis zur Anfechtung.' }, { feld: 'optionen', id: 'opt-2', text: 'Falsch — nichtige Verträge können nicht durch Ratifizierung geheilt werden.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Nichtigkeit bei fehlenden Voraussetzungen, Anfechtbarkeit bei Willensmängeln.' } ] },
  { id: '93a285ab-46c2-4798-9a78-95b528166b98', fachbereich: 'Recht', musterlosung: 'Nach Art. 2 Abs. 2 ZGB liegt Rechtsmissbrauch erst vor, wenn ein krass stossendes Verhalten vorliegt. Nicht jede harte Folge für den anderen ist Rechtsmissbrauch. Die Grenze ist hoch: Das Gericht greift nur bei offensichtlich missbräuchlichem Verhalten ein — «offenbarer Missbrauch», wie der Gesetzeswortlaut sagt.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Zweck-Motivation allein reicht nicht — das Verhalten muss krass stossend sein.' }, { feld: 'optionen', id: 'opt-1', text: 'Harte Folgen sind noch kein Rechtsmissbrauch — die Schwelle liegt höher.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Erst krass stossendes Verhalten begründet Rechtsmissbrauch.' }, { feld: 'optionen', id: 'opt-3', text: 'Verspätete Ausübung ist nicht per se Missbrauch — widersprüchliches Verhalten wäre ein Unterfall.' } ] },
  { id: '93db38b0-09a0-4d19-85ca-6ce07f358aa3', fachbereich: 'Recht', musterlosung: 'Der Geliebte ist Anstifter nach Art. 24 StGB. Er hat durch wiederholtes Einreden auf die Frau eingewirkt, bis sie den Entschluss fasste, eine strafbare Handlung zu begehen. Der Anstifter wird gleich bestraft wie der Haupttäter, die Strafzumessung erfolgt aber individuell. Die Anstiftung ist eine eigenständige Strafform — nicht die Straffreiheit.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Nicht straffrei — Anstiftung ist eigenständige Strafform (Art. 24 StGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Anstifter weckt den Tatentschluss beim Haupttäter durch Überredung.' }, { feld: 'optionen', id: 'opt-2', text: 'Keine Gehilfenschaft — er half nicht bei der Durchführung, sondern löste den Entschluss aus.' }, { feld: 'optionen', id: 'opt-3', text: 'Keine Mittäterschaft — ohne Tatherrschaft bei der Ausführung.' } ] },
  { id: '94ded063-d2eb-4103-8e50-fc1c67bea7a6', fachbereich: 'Recht', musterlosung: 'Ein gültig geschlossener Mietvertrag bindet Sandra. Die Kündigungsfrist beträgt bei Wohnungen 3 Monate auf Ende eines Monats (Art. 266c OR). Sofort-Kündigung ab November wirkt frühestens auf Ende Januar. Sandra muss die Miete bis Ende Januar bezahlen, ausser sie stellt einen zumutbaren Nachmieter (Art. 264 OR).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Kostenlose Stornierung ist ohne Vereinbarung nicht möglich — der Vertrag bindet.' }, { feld: 'optionen', id: 'opt-1', text: '1 Monat reicht nicht — 3 Monate Kündigungsfrist (Art. 266c OR).' }, { feld: 'optionen', id: 'opt-2', text: 'Ende Februar wäre 4 Monate — die Kündigungsfrist ist 3 Monate.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: 3 Monate ab November → Ende Januar.' } ] },
  { id: '94df370b-eb04-4591-b5fb-839b667f64c9', fachbereich: 'Recht', musterlosung: 'Nach OR 336c ist eine Kündigung während Krankheit nichtig. Die Sperrfrist dauert gestaffelt nach Dienstjahren: 30 Tage im 1. Dienstjahr, 90 Tage im 2.–5. Dienstjahr, 180 Tage ab dem 6. Dienstjahr. Während dieser Zeit ist eine Kündigung absolut unzulässig und nichtig.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: '30 Tage gelten nur im 1. Dienstjahr — nicht generell.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Die Sperrfrist schützt während der Krankheit (gestaffelt nach Dienstjahren).' }, { feld: 'optionen', id: 'opt-2', text: 'Die Sperrfrist ist fest gestaffelt — nicht an die Berner Skala der Lohnfortzahlung gekoppelt.' }, { feld: 'optionen', id: 'opt-3', text: 'Eine Kündigung während Krankheit ist nichtig — Schutz wirkt.' } ] },
  { id: '9595f089-dfc4-4ac4-8c81-39a0abd8a5bb', fachbereich: 'Recht', musterlosung: 'Verordnungen enthalten detaillierte Ausführungsbestimmungen zu einem Gesetz und konkretisieren dessen Inhalt. Da sie hierarchisch unter dem Gesetz stehen und dessen Anwendung regeln, benötigen sie eine ausdrückliche gesetzliche Grundlage. Ohne Gesetz gibt es keine legitime Verordnungskompetenz.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Verordnungen werden gezielt zu einem bestimmten Gesetz erlassen — der Bundesrat kennt das Thema.' }, { feld: 'optionen', id: 'opt-1', text: 'Nicht nur Verfassungsvorschrift — es folgt aus der Hierarchie der Rechtsquellen.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Verordnung konkretisiert Gesetz und braucht dessen Grundlage.' }, { feld: 'optionen', id: 'opt-3', text: 'Das Parlament genehmigt Verordnungen nicht einzeln — die Delegation erfolgt im Gesetz.' } ] },
  { id: '95c6bdc7-4374-4d00-98e6-de69ae6a2c87', fachbereich: 'Recht', musterlosung: 'Um einen Entscheid anzufechten, muss der Steuerpflichtige innerhalb der Frist ordentliche Einsprache beim kantonalen Steueramt erheben. Unterlässt er dies, erwächst der Einschätzungsentscheid in Rechtskraft. Der Instanzenzug muss durchlaufen werden — ein direkter Gang zum Bundesgericht ist nicht möglich.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Keine automatische Überprüfung — der Steuerpflichtige muss aktiv werden.' }, { feld: 'optionen', id: 'opt-1', text: 'Persönliche Bitte ist kein Rechtsmittel — Form und Frist sind einzuhalten.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Fristgerechte schriftliche Einsprache beim kantonalen Steueramt.' }, { feld: 'optionen', id: 'opt-3', text: 'Kein direkter Zugang zum Bundesgericht — Instanzenzug beachten.' } ] },
  { id: '969476b6-3838-4801-8131-f588e2e1cf19', fachbereich: 'Recht', musterlosung: 'Nach Art. 958 ZGB werden im Grundbuch eingetragen: Eigentum, Dienstbarkeiten, Grundlasten und Pfandrechte. Miet- und Arbeitsverträge sind obligatorische Rechte und werden nicht grundbuchlich eingetragen. Bestimmte obligatorische Rechte wie Vorkaufs- oder Mietrechte können aber als Vormerkung eingetragen werden (Art. 959–961 ZGB).', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Eigentum ist grundbuchpflichtig.' }, { feld: 'optionen', id: 'opt-1', text: 'Korrekt: Dienstbarkeiten und Grundlasten werden im Grundbuch geführt.' }, { feld: 'optionen', id: 'opt-2', text: 'Korrekt: Pfandrechte (Grundpfand) sind im Grundbuch eingetragen.' }, { feld: 'optionen', id: 'opt-3', text: 'Miet- und Arbeitsverträge sind obligatorische Rechte — nicht grundbuchlich.' } ] },
  { id: '971c9097-5b66-40b3-ab90-4fb82394041f', fachbereich: 'Recht', musterlosung: 'Beim Auftrag (OR 394–406) schuldet der Beauftragte nur sorgfältige Ausführung einer Tätigkeit — nicht ein bestimmtes Ergebnis (wie beim Werkvertrag) oder Unterordnung (wie beim Arbeitsvertrag). Er ist selbstständig und weisungsfrei tätig. Ein Steuerberater ohne Unterordnung erfüllt typische Auftragsmerkmale.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Dienstverhältnis ist kein spezifischer BV-Begriff — hier irrelevant.' }, { feld: 'optionen', id: 'opt-1', text: 'Werkvertrag schuldet ein Ergebnis (Werk) — hier keine spezifische Werkleistung.' }, { feld: 'optionen', id: 'opt-2', text: 'Kein Arbeitsvertrag — es fehlt die Unterordnung und Weisungsgebundenheit.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Auftrag (OR 394 ff.) — selbstständig, sorgfältige Tätigkeit.' } ] },
  { id: '9853d2cb-fa51-47e5-8528-d1fdf696b883', fachbereich: 'Recht', musterlosung: 'Handlungsfähigkeit setzt Urteilsfähigkeit voraus (Art. 13 ZGB). Wer aufgrund von Rausch nicht vernunftgemäss handeln kann, ist urteilsunfähig (Art. 16 ZGB) — und damit handlungsunfähig. Ein von einer handlungsunfähigen Person abgeschlossener Vertrag ist nichtig (Art. 18 ZGB). Die Schriftform ändert daran nichts. Hans muss seine Urteilsunfähigkeit allerdings beweisen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Urteilsunfähigkeit durch Rausch → Nichtigkeit (Art. 18 ZGB).' }, { feld: 'optionen', id: 'opt-1', text: 'Alkoholkonsum kann sehr wohl zur Urteilsunfähigkeit führen.' }, { feld: 'optionen', id: 'opt-2', text: 'Schriftform hebt die Urteilsunfähigkeit nicht auf.' }, { feld: 'optionen', id: 'opt-3', text: 'Der Ort des Vertragsschlusses ist unerheblich — die Urteilsfähigkeit zählt.' } ] },
  { id: '98b3af83-0783-48b9-beef-c8a4fb605bc8', fachbereich: 'Recht', musterlosung: 'Art. 36 BV regelt die Voraussetzungen für Grundrechtseinschränkungen: gesetzliche Grundlage (Abs. 1), öffentliches Interesse oder Schutz von Grundrechten Dritter (Abs. 2), Verhältnismässigkeit (Abs. 3) und Unantastbarkeit des Kerngehalts (Abs. 4). Dieser Artikel ist zentraler Prüfungsmasstab für jede Grundrechtsbeschränkung.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Art. 5 BV regelt Grundsätze rechtsstaatlichen Handelns allgemein.' }, { feld: 'optionen', id: 'opt-1', text: 'Art. 7 BV regelt die Menschenwürde — Grundrecht, nicht Einschränkungsregel.' }, { feld: 'optionen', id: 'opt-2', text: 'Art. 190 BV betrifft massgebendes Recht für Bundesgericht.' }, { feld: 'optionen', id: 'opt-3', text: 'Korrekt: Art. 36 BV = Voraussetzungen für Grundrechtseinschränkungen.' } ] },
  { id: '98c49568-38fb-4f62-923c-5ce20aacf274', fachbereich: 'Recht', musterlosung: 'Nach OR 330a muss ein Arbeitszeugnis wahr, klar, vollständig und in wohlwollender (schonender) Form formuliert sein. Es darf weder böswillig schlecht noch falsch positiv sein — Wahrheit und Wohlwollen müssen in Balance stehen. Der Arbeitnehmer hat Anspruch auf ein solches Vollzeugnis.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Wahr, klar, vollständig und wohlwollend (OR 330a).' }, { feld: 'optionen', id: 'opt-1', text: 'Nur Positives wäre falsch positiv — verletzt die Wahrheitspflicht.' }, { feld: 'optionen', id: 'opt-2', text: 'Unvollständig — auch Leistung und Verhalten gehören ins Vollzeugnis.' }, { feld: 'optionen', id: 'opt-3', text: 'Reine Aufzählung von Fehlverhalten verletzt die Wohlwollenspflicht.' } ] },
  { id: '99842881-2303-4de9-b14b-69b8a1fde0b4', fachbereich: 'Recht', musterlosung: 'Der Streitwert liegt mit CHF 1\'200 unter CHF 30\'000 — es gilt das vereinfachte Verfahren (Art. 243 ZPO). Die örtliche Zuständigkeit liegt grundsätzlich am Wohnsitz der beklagten Partei (Art. 10 ZPO), also in Zürich. Elena muss deshalb beim Gericht in Zürich klagen.', teilerklaerungen: [ { feld: 'optionen', id: 'opt-0', text: 'Korrekt: Vereinfachtes Verfahren (bis CHF 30\'000) am Beklagtenwohnsitz (Zürich).' }, { feld: 'optionen', id: 'opt-1', text: 'Örtliche Zuständigkeit ist am Beklagtenwohnsitz — nicht beim Kläger.' }, { feld: 'optionen', id: 'opt-2', text: 'Falscher Gerichtsstand + falsches Verfahren.' }, { feld: 'optionen', id: 'opt-3', text: 'Streitwert zu niedrig fürs ordentliche Verfahren — vereinfacht gilt.' } ] },
]

// Duplikate filtern (sollte bei dieser Session nicht vorkommen, aber defensiv)
const seen = new Set()
const filtered = updates.filter((u) => {
  if (seen.has(u.id)) return false
  seen.add(u.id)
  return true
})

const lines = filtered.map((u) => JSON.stringify(u)).join('\n') + '\n'
await fs.appendFile(OUT, lines)

const state = JSON.parse(await fs.readFile(STATE, 'utf8'))
state.letzteSession = new Date().toISOString()
state.verarbeitet = (state.verarbeitet || 0) + filtered.length
state.fragen = state.fragen || {}
for (const u of filtered) {
  state.fragen[u.id] = { status: 'done', zeitpunkt: state.letzteSession, teile: u.teilerklaerungen.length }
}
await fs.writeFile(STATE, JSON.stringify(state, null, 2))
console.log(`[s5] ${filtered.length} Updates | total ${state.verarbeitet}/${state.totalFragen}`)
